import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, Zap, AlignLeft, X, Activity } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';
import { ProcessedInput } from '../types';

interface VoiceCaptureProps {
  onProcessed: (result: ProcessedInput) => void;
}

const VoiceCapture: React.FC<VoiceCaptureProps> = ({ onProcessed }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [volume, setVolume] = useState(0);
  const [transcript, setTranscript] = useState<string>('');
  const [modelStatus, setModelStatus] = useState<'listening' | 'processing' | 'speaking'>('listening');

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const mountedRef = useRef(true);

  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
      stopSession();
    };
  }, []);

  const captureTool: FunctionDeclaration = {
    name: 'capture_items',
    description: 'Extracts tasks, habits, and notes from user voice input.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        items: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
              content: { type: Type.STRING, description: "The main text of the item" },
              description: { type: Type.STRING, description: "Any additional details mentioned" },
              priority: { type: Type.INTEGER, description: "1 (High) to 4 (Low)" },
              dueDate: { type: Type.STRING, description: "YYYY-MM-DD format if mentioned" },
              streak: { type: Type.INTEGER },
              frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["type", "content"]
          }
        }
      },
      required: ['items']
    }
  };

  const startSession = async () => {
    try {
      setIsConnecting(true);

      // 1. Setup Audio Input (16kHz)
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = audioContext;

      const source = audioContext.createMediaStreamSource(stream);
      const processor = audioContext.createScriptProcessor(4096, 1, 1);
      processorRef.current = processor;

      source.connect(processor);
      processor.connect(audioContext.destination);

      // 2. Connect to Gemini Live
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
          },
          inputAudioTranscription: { model: "gemini-2.5-flash-native-audio-preview-12-2025" },
          outputAudioTranscription: { model: "gemini-2.5-flash-native-audio-preview-12-2025" },
          tools: [{ functionDeclarations: [captureTool] }],
          systemInstruction: `
            You are EchoFlow, an intelligent productivity assistant.
            Your goal is to capture tasks, habits, and notes immediately as the user speaks.

            RULES:
            1. Listen intently.
            2. When the user mentions a task (e.g., "Remind me to call Mom"), IMMEDIATEY call the 'capture_items' tool. Do not wait for a pause.
            3. You can capture multiple times in one session.
            4. Keep your audio responses extremely brief and confirming (e.g., "Added", "Got it", "Done").
            5. If the user asks a question, answer briefly.
          `,
        },
        callbacks: {
            onopen: () => {
                if(mountedRef.current) {
                    setIsActive(true);
                    setIsConnecting(false);
                    nextStartTimeRef.current = audioContext.currentTime;
                }
            },
            onmessage: async (msg: LiveServerMessage) => {
                // Handle Tool Calls
                if (msg.toolCall) {
                    msg.toolCall.functionCalls.forEach(fc => {
                        if (fc.name === 'capture_items') {
                            const args = fc.args as unknown as ProcessedInput;
                            onProcessed(args);

                            // Send success response
                            sessionPromise.then(session => {
                                session.sendToolResponse({
                                    functionResponses: {
                                        id: fc.id,
                                        name: fc.name,
                                        response: { result: "Success" }
                                    }
                                });
                            });
                        }
                    });
                }

                // Handle Audio Output
                const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (audioData && audioContextRef.current) {
                    setModelStatus('speaking');
                    const buffer = await decodeAudioData(audioData, audioContextRef.current);
                    playAudio(buffer, audioContextRef.current);
                }

                // Handle Transcription
                const inputTranscript = msg.serverContent?.inputTranscription?.text;
                if (inputTranscript) {
                    setTranscript(prev => `You: ${inputTranscript}`);
                    setModelStatus('listening');
                }
            },
            onclose: () => {
                if(mountedRef.current) stopSession();
            },
            onerror: (err) => {
                console.error("Live API Error", err);
                if(mountedRef.current) stopSession();
            }
        }
      });

      sessionRef.current = sessionPromise;

      // 3. Stream Audio
      processor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);

        // Calculate Volume
        let sum = 0;
        for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
        if (mountedRef.current) setVolume(Math.sqrt(sum / inputData.length));

        // Encode and Send
        const base64Data = encodeAudio(inputData);
        sessionPromise.then(session => {
             session.sendRealtimeInput({
                media: {
                    mimeType: 'audio/pcm;rate=16000',
                    data: base64Data
                }
             });
        });
      };

    } catch (e) {
      console.error("Failed to start session", e);
      setIsConnecting(false);
      setIsActive(false);
    }
  };

  const stopSession = () => {
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }
    if (processorRef.current) {
        processorRef.current.disconnect();
        processorRef.current = null;
    }
    if (audioContextRef.current) {
        audioContextRef.current.close();
        audioContextRef.current = null;
    }
    setIsActive(false);
    setIsConnecting(false);
    setVolume(0);
    setTranscript('');
    sessionRef.current = null;
  };

  // Audio Helpers
  const encodeAudio = (inputData: Float32Array): string => {
    const l = inputData.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      const s = Math.max(-1, Math.min(1, inputData[i]));
      int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    let binary = '';
    const bytes = new Uint8Array(int16.buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return window.btoa(binary);
  };

  const decodeAudioData = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }

    // Create AudioBuffer from raw PCM 24kHz (Model default)
    // Note: Live API Audio is typically 24kHz.
    const dataInt16 = new Int16Array(bytes.buffer);
    const float32 = new Float32Array(dataInt16.length);
    for (let i = 0; i < dataInt16.length; i++) {
        float32[i] = dataInt16[i] / 32768.0;
    }

    const buffer = ctx.createBuffer(1, float32.length, 24000);
    buffer.copyToChannel(float32, 0);
    return buffer;
  };

  const playAudio = (buffer: AudioBuffer, ctx: AudioContext) => {
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);

    // Schedule
    const now = ctx.currentTime;
    // If nextStartTime is in the past, reset it to now
    if (nextStartTimeRef.current < now) {
        nextStartTimeRef.current = now;
    }

    source.start(nextStartTimeRef.current);
    nextStartTimeRef.current += buffer.duration;

    source.onended = () => {
        if (ctx.currentTime >= nextStartTimeRef.current) {
             setModelStatus('listening');
        }
    };
  };

  return (
    <div className="fixed bottom-0 left-0 md:left-[260px] right-0 p-6 flex flex-col items-center justify-end z-30 pointer-events-none">

       {/* Transcript / Status Overlay */}
       {isActive && (
           <div className="pointer-events-auto mb-6 bg-zinc-900/90 backdrop-blur-xl text-white px-6 py-4 rounded-3xl shadow-2xl flex flex-col items-center gap-2 animate-in slide-in-from-bottom-10 fade-in duration-300 border border-zinc-800 max-w-lg w-full text-center">
               <div className="flex items-center gap-2 mb-1">
                   {modelStatus === 'listening' && (
                        <span className="flex items-center gap-1.5 text-xs font-bold uppercase tracking-wider text-emerald-400">
                             <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"/>
                             Listening
                        </span>
                   )}
                   {modelStatus === 'speaking' && (
                        <span className="flex items-center gap-1.5 text-xs font-bold uppercase tracking-wider text-sky-400">
                             <Activity size={12} className="animate-bounce" />
                             Speaking
                        </span>
                   )}
               </div>

               {transcript ? (
                   <p className="text-sm font-medium text-zinc-100 leading-relaxed transition-all">
                       {transcript}
                   </p>
               ) : (
                   <p className="text-sm text-zinc-500 italic">Say "Add task buy milk"...</p>
               )}

               {/* Visualizer */}
               <div className="flex items-center gap-1 h-8 mt-2">
                   {[...Array(8)].map((_, i) => (
                       <div 
                           key={i}
                           className={`w-1.5 rounded-full transition-all duration-75 ${modelStatus === 'speaking' ? 'bg-sky-400' : 'bg-emerald-500'}`}
                           style={{ 
                               height: `${Math.max(20, Math.min(100, volume * 1000 * (Math.random() + 0.5)))}%`,
                               opacity: 0.8 
                           }}
                       />
                   ))}
               </div>
           </div>
       )}

      {/* Main Control */}
      <div className="pointer-events-auto flex items-center gap-4">
        <button
            onClick={isActive ? stopSession : startSession}
            className={`
            relative flex items-center justify-center w-16 h-16 rounded-full shadow-2xl transition-all duration-300 transform
            ${isActive 
                ? 'bg-zinc-800 text-rose-500 ring-4 ring-rose-500/20 scale-100 hover:scale-105' 
                : isConnecting 
                    ? 'bg-zinc-100 dark:bg-dark-surface text-zinc-400 scale-95' 
                    : 'bg-brand-600 text-white hover:bg-brand-700 hover:scale-110 shadow-brand-500/40'
            }
            `}
        >
            {isConnecting ? (
                <Loader2 size={24} className="animate-spin" />
            ) : isActive ? (
                <X size={24} strokeWidth={3} />
            ) : (
                <Mic size={28} />
            )}
        </button>
      </div>

      <div className="h-6 mt-4 text-xs font-medium text-zinc-400 dark:text-zinc-500 text-center transition-opacity duration-300">
        {isActive ? "Tap to close" : "Tap to speak"}
      </div>
    </div>
  );
};

