import { GoogleGenAI, Type } from "@google/genai";
import { ProcessedInput, Priority, ParsedTask } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const processTextEntry = async (textInput: string): Promise<ProcessedInput | null> => {
    const now = new Date();
    const dateContext = `Today is ${now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}.`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `
                Analyze this input for EchoFlow: "${textInput}". 
                ${dateContext}
                Classify into tasks, notes, or habits. 
                For tasks, calculate precise YYYY-MM-DD due dates if relative time is mentioned (e.g. "next Monday").
                For habits, detect frequency (daily, weekly, monthly).
            `,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        items: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
                                    content: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    priority: { type: Type.INTEGER },
                                    dueDate: { type: Type.STRING },
                                    mood: { type: Type.STRING },
                                    streak: { type: Type.INTEGER },
                                    frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
                                    tags: { type: Type.ARRAY, items: { type: Type.STRING } }
                                },
                                required: ["type", "content"]
                            }
                        }
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : null;
    } catch (e) {
        console.error("Text processing error", e);
        return null;
    }
}

export const parseTaskWithGemini = async (rawInput: string, projectNames: string[]): Promise<ParsedTask | null> => {
  const now = new Date();
  const dateContext = `Today is ${now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `
        You are a smart task parser.
        ${dateContext}
        Spaces: ${JSON.stringify(projectNames)}

        Input: "${rawInput}"

        Extract:
        - content: clear task title
        - description: extra details
        - priority: 1 (Urgent) to 4 (Low). Default 4.
        - dueDate: YYYY-MM-DD (Calculate based on today's date)
        - projectName: Exact match from provided list if applicable (Spaces)
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            content: { type: Type.STRING },
            description: { type: Type.STRING },
            priority: { type: Type.INTEGER },
            dueDate: { type: Type.STRING },
            projectName: { type: Type.STRING }
          },
          required: ["content"]
        }
      }
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("Task parsing error", error);
    return null;
  }
};

export const suggestSubtasks = async (taskContent: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `List 3-5 subtasks for: "${taskContent}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return response.text ? JSON.parse(response.text) : [];
  } catch (error) {
    console.error("Subtask suggestion error", error);
    return [];
  }
};

{
  "name": "EchoFlow",
  "description": "Your AI-powered mental inbox. Capture tasks, thoughts, and reflections.",
  "requestFramePermissions": []
}

export enum Priority {
  P1 = 1, // Critical
  P2 = 2, // High
  P3 = 3, // Medium
  P4 = 4  // Low
}

export type ItemType = 'TASK' | 'NOTE' | 'HABIT';
export type HabitFrequency = 'daily' | 'weekly' | 'monthly';

export interface FlowItem {
  id: string;
  type: ItemType;
  content: string;
  description?: string; // Additional context or AI summary

  // Task specific
  isCompleted?: boolean;
  priority?: Priority;
  dueDate?: string; // ISO Date string
  projectId?: string; // Linked Project ID

  // Habit specific
  streak?: number;
  lastCompletedDate?: string; // YYYY-MM-DD
  frequency?: HabitFrequency;
  history?: string[]; // Array of YYYY-MM-DD completion dates for graph

  // Metadata
  tags?: string[];
  createdAt: string;
  mood?: 'neutral' | 'positive' | 'negative' | 'focused' | 'anxious'; // AI inferred mood
}

export interface Project {
  id: string;
  name: string;
  color: string;
}

export interface ParsedTask {
  content: string;
  description?: string;
  priority?: Priority;
  dueDate?: string;
  projectName?: string;
}

export type Task = FlowItem;

export interface ViewState {
  type: 'HOME' | 'TASKS' | 'HABITS' | 'JOURNAL' | 'PROJECT' | 'TAG' | 'CALENDAR';
  id?: string; // projectId or tagName
}

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Menu, Plus, LayoutGrid, Search, Moon, Sun, X, CheckCircle2, CalendarDays } from 'lucide-react';
import Sidebar from './components/Sidebar';
import FlowItem from './components/FlowItem';
import AddTask from './components/AddTask';
import ProjectModal from './components/ProjectModal';
import HomeDashboard from './components/HomeDashboard';
import CalendarView from './components/CalendarView';
import { FlowItem as FlowItemType, ViewState, Priority, Project, HabitFrequency } from './types';

const INITIAL_PROJECTS: Project[] = [
    { id: 'p-personal', name: 'Personal', color: '#10b981' }, // Emerald
    { id: 'p-work', name: 'Work', color: '#3b82f6' } // Blue
];

const INITIAL_ITEMS: FlowItemType[] = [
  {
    id: 'welcome-1',
    type: 'TASK',
    content: 'Welcome to EchoFlow',
    description: 'A calm, intelligent space for your thoughts. Use the + button to capture tasks.',
    priority: Priority.P1,
    createdAt: new Date().toISOString(),
    isCompleted: false,
    projectId: 'p-personal',
    tags: ['welcome']
  },
  {
      id: 'habit-1',
      type: 'HABIT',
      content: 'Morning Focus',
      streak: 3,
      frequency: 'daily',
      history: [
          new Date(Date.now() - 86400000).toISOString().split('T')[0],
          new Date(Date.now() - 172800000).toISOString().split('T')[0],
          new Date(Date.now() - 259200000).toISOString().split('T')[0]
      ],
      createdAt: new Date().toISOString()
  }
];

const App: React.FC = () => {
  const [items, setItems] = useState<FlowItemType[]>(() => {
    const saved = localStorage.getItem('echoflow_items');
    return saved ? JSON.parse(saved) : INITIAL_ITEMS;
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('echoflow_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });

  const [karma, setKarma] = useState<number>(() => {
      const saved = localStorage.getItem('echoflow_karma');
      return saved ? parseInt(saved) : 0;
  });

  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [habitTab, setHabitTab] = useState<HabitFrequency>('daily');
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [darkMode, setDarkMode] = useState(() => {
      if (typeof window !== 'undefined') {
          return localStorage.getItem('echoflow_theme') === 'dark' || 
                 (!('echoflow_theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches);
      }
      return false;
  });

  // Toast State
  const [toast, setToast] = useState<{message: string, type: 'success' | 'info'} | null>(null);

  useEffect(() => {
    localStorage.setItem('echoflow_items', JSON.stringify(items));
    localStorage.setItem('echoflow_projects', JSON.stringify(projects));
    localStorage.setItem('echoflow_karma', karma.toString());
  }, [items, projects, karma]);

  // Dark Mode Effect
  useEffect(() => {
      if (darkMode) {
          document.documentElement.classList.add('dark');
          localStorage.setItem('echoflow_theme', 'dark');
      } else {
          document.documentElement.classList.remove('dark');
          localStorage.setItem('echoflow_theme', 'light');
      }
  }, [darkMode]);

  const showToast = (message: string, type: 'success' | 'info' = 'success') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 3000);
  };

  const handleAddTask = (taskData: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => {
    const newTask: FlowItemType = {
        id: uuidv4(),
        type: 'TASK',
        content: taskData.content,
        description: taskData.description,
        priority: taskData.priority,
        projectId: taskData.projectId === 'inbox' ? 'inbox' : taskData.projectId,
        dueDate: taskData.dueDate,
        createdAt: new Date().toISOString(),
        isCompleted: false,
        tags: [] 
    };
    setItems(prev => [newTask, ...prev]);
    setShowAddTask(false);
    showToast('Task added');
  };

  const handleUpdateItem = (id: string, updates: Partial<FlowItemType>) => {
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
      showToast('Item updated', 'info');
  };

  const handleMoveTask = (id: string, newDate: string) => {
      setItems(prev => prev.map(item => item.id === id ? { ...item, dueDate: newDate } : item));
      showToast('Rescheduled');
  };

  const handleAddProject = (name: string, color: string) => {
    const newProject = { id: uuidv4(), name, color };
    setProjects(prev => [...prev, newProject]);
    showToast(`Space "${name}" created`);
  };

  const handleComplete = (id: string) => {
    setItems(prev => prev.map(item => {
      if (item.id !== id) return item;

      const isCompleting = !item.isCompleted;
      const today = new Date().toISOString().split('T')[0];

      if (item.type === 'HABIT') {
        const history = item.history || [];
        const isDoneToday = history.includes(today);

        let newHistory = [...history];
        let newStreak = item.streak || 0;

        if (isDoneToday) {
            // Uncheck: Remove today
            newHistory = newHistory.filter(d => d !== today);
            newStreak = Math.max(0, newStreak - 1);
            setKarma(k => Math.max(0, k - 50));
        } else {
            // Check: Add today
            newHistory.push(today);
            newStreak += 1;
            showToast('Streak increased! 🌿');
            setKarma(k => k + 50);
        }

        // Sort history
        newHistory.sort();

        return {
            ...item,
            streak: newStreak,
            history: newHistory,
            lastCompletedDate: isDoneToday ? undefined : today
        };
      }

      if (isCompleting) {
          showToast('Completed', 'success');
          setKarma(k => k + 25);
      } else {
          setKarma(k => Math.max(0, k - 25));
      }

      return { ...item, isCompleted: isCompleting };
    }));
  };

  const handleDelete = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
    showToast('Deleted', 'info');
  };

  const filteredItems = useMemo(() => {
    let baseItems = items;

    // Search Filter
    if (searchQuery.trim()) {
        const q = searchQuery.toLowerCase();
        baseItems = baseItems.filter(i => 
            i.content.toLowerCase().includes(q) || 
            i.description?.toLowerCase().includes(q) ||
            i.tags?.some(t => t.toLowerCase().includes(q))
        );
    }

    // View Logic Filter
    switch (viewState.type) {
        case 'HOME':
            // Dashboard handles its own filtering
            return baseItems;
        case 'TASKS':
             baseItems = baseItems.filter(i => i.type === 'TASK' && !i.isCompleted);
             break;
        case 'HABITS':
            baseItems = baseItems.filter(i => i.type === 'HABIT' && (i.frequency || 'daily') === habitTab);
            break;
        case 'JOURNAL':
            baseItems = baseItems.filter(i => i.type === 'NOTE');
            break;
        case 'PROJECT':
            baseItems = baseItems.filter(i => i.projectId === viewState.id && !i.isCompleted);
            break;
        case 'TAG':
            baseItems = baseItems.filter(i => i.tags?.includes(viewState.id || '') && !i.isCompleted);
            break;
        case 'CALENDAR':
            return baseItems.filter(i => i.type === 'TASK' && !i.isCompleted);
    }
    return baseItems;
  }, [items, viewState, habitTab, searchQuery]);

  const getPageTitle = () => {
      if (searchQuery) return 'Search Results';
      switch (viewState.type) {
          case 'HOME': return 'Dashboard';
          case 'TASKS': return 'My Tasks';
          case 'HABITS': return 'Habits';
          case 'JOURNAL': return 'Journal';
          case 'CALENDAR': return 'Calendar';
          case 'PROJECT': return projects.find(p => p.id === viewState.id)?.name || 'Space';
          case 'TAG': return `# ${viewState.id}`;
          default: return 'Home';
      }
  };

  return (
    <div className="flex flex-col h-screen bg-zinc-50 dark:bg-dark-bg text-zinc-900 dark:text-zinc-100 transition-colors duration-200 font-sans">
      {/* Header */}
      <header className="h-16 px-4 md:px-8 bg-white/80 dark:bg-dark-surface/80 backdrop-blur-md border-b border-zinc-200 dark:border-dark-border flex items-center justify-between z-20 sticky top-0">
          <div className="flex items-center gap-4">
            <button 
                onClick={() => setIsMobileOpen(!isMobileOpen)}
                className="p-2 hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight rounded-xl transition-colors md:hidden text-zinc-600 dark:text-zinc-400"
            >
                <Menu size={24} />
            </button>
            <div 
                className="flex items-center gap-2 cursor-pointer group"
                onClick={() => setViewState({type: 'HOME'})}
            >
                <div className="w-8 h-8 rounded-xl bg-brand-500 flex items-center justify-center text-white shadow-lg shadow-brand-500/20 group-hover:scale-105 transition-transform">
                    <span className="font-bold">E</span>
                </div>
                <span className="font-bold text-lg tracking-tight hidden md:block text-zinc-800 dark:text-zinc-100">EchoFlow</span>
            </div>

            <div className="relative ml-4 md:ml-8 hidden md:block group">
                <input 
                    id="header-search"
                    type="text" 
                    placeholder="Search..." 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className={`
                        bg-zinc-100 dark:bg-dark-surfaceHighlight text-zinc-800 dark:text-zinc-200 placeholder-zinc-400 rounded-xl pl-10 pr-4 py-2 text-sm 
                        focus:outline-none focus:ring-2 focus:ring-brand-500/50 focus:bg-white dark:focus:bg-dark-surface w-64 transition-all duration-300
                    `}
                />
                <Search size={16} className="absolute left-3 top-2.5 text-zinc-400 pointer-events-none group-focus-within:text-brand-500 transition-colors" />
                {searchQuery && (
                    <button onClick={() => setSearchQuery('')} className="absolute right-3 top-2.5 text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-200">
                        <X size={14} />
                    </button>
                )}
            </div>
          </div>

          <div className="flex items-center gap-3">
              <button 
                onClick={() => setDarkMode(!darkMode)}
                className="p-2.5 text-zinc-500 dark:text-zinc-400 hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight rounded-xl transition-colors"
                title="Toggle Theme"
              >
                  {darkMode ? <Sun size={20} /> : <Moon size={20} />}
              </button>
              <button className="hidden md:flex items-center gap-2 px-4 py-2 bg-brand-600 text-white rounded-xl font-semibold text-sm hover:bg-brand-700 shadow-lg shadow-brand-500/20 transition-all hover:translate-y-[-1px]" onClick={() => setShowAddTask(true)}>
                  <Plus size={18} />
                  <span>New Item</span>
              </button>
              <button className="md:hidden p-2.5 bg-brand-600 text-white rounded-xl shadow-lg shadow-brand-500/20" onClick={() => setShowAddTask(true)}>
                  <Plus size={20} />
              </button>
          </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        <Sidebar 
            currentView={viewState}
            projects={projects}
            onViewChange={(view) => { setViewState(view); setSearchQuery(''); }}
            onAddProject={() => setIsProjectModalOpen(true)}
            isMobileOpen={isMobileOpen}
            onCloseMobile={() => setIsMobileOpen(false)}
            karma={karma}
        />

        <main className="flex-1 flex flex-col relative w-full h-full overflow-hidden">
            <div className="flex-1 overflow-y-auto scrollbar-hide z-10">

                {/* Dashboard View */}
                {viewState.type === 'HOME' && !searchQuery ? (
                    <HomeDashboard 
                        items={items}
                        onNavigate={setViewState}
                        onComplete={handleComplete}
                    />
                ) : viewState.type === 'CALENDAR' && !searchQuery ? (
                    /* Calendar View */
                    <CalendarView 
                        items={filteredItems}
                        projects={projects}
                        onMoveTask={handleMoveTask}
                        onComplete={handleComplete}
                    />
                ) : (
                    /* List View for Tasks/Habits/Projects */
                    <div className="max-w-[800px] mx-auto px-4 md:px-8 pt-8 pb-40">
                        <div className="mb-6 flex items-end justify-between">
                            <div>
                                <h1 className="text-2xl font-bold text-zinc-800 dark:text-white mb-1 flex items-center gap-3">
                                    {getPageTitle()}
                                </h1>
                                <p className="text-zinc-500 dark:text-zinc-400 text-sm">
                                    {filteredItems.length} items
                                </p>
                            </div>

                            {/* Habit Tabs */}
                            {viewState.type === 'HABITS' && (
                                <div className="flex bg-zinc-200 dark:bg-dark-surfaceHighlight p-1 rounded-lg">
                                    {(['daily', 'weekly', 'monthly'] as HabitFrequency[]).map(tab => (
                                        <button
                                            key={tab}
                                            onClick={() => setHabitTab(tab)}
                                            className={`px-3 py-1 text-xs font-bold uppercase tracking-wide rounded-md transition-all ${
                                                habitTab === tab 
                                                ? 'bg-white dark:bg-dark-surface text-brand-600 dark:text-brand-400 shadow-sm' 
                                                : 'text-zinc-500 dark:text-zinc-400 hover:text-zinc-700 dark:hover:text-zinc-200'
                                            }`}
                                        >
                                            {tab}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Inline Add Task Trigger */}
                        {!showAddTask && !searchQuery && viewState.type !== 'HOME' && viewState.type !== 'CALENDAR' && (
                             <button 
                                onClick={() => setShowAddTask(true)}
                                className="group w-full mb-4 flex items-center gap-3 p-3 rounded-xl border-2 border-dashed border-zinc-200 dark:border-dark-border text-zinc-400 hover:text-brand-600 hover:border-brand-200 hover:bg-brand-50/50 dark:hover:bg-brand-900/10 transition-all"
                            >
                                <div className="w-6 h-6 rounded-lg bg-zinc-100 dark:bg-dark-surface flex items-center justify-center group-hover:bg-brand-100 dark:group-hover:bg-brand-900/50 transition-colors">
                                    <Plus size={14} />
                                </div>
                                <span className="font-medium text-sm">Capture something...</span>
                            </button>
                        )}

                        {/* Add Task Form */}
                        {showAddTask && (
                            <div className="mb-6">
                                <AddTask 
                                    projects={projects}
                                    defaultProjectId={viewState.type === 'PROJECT' && viewState.id ? viewState.id : 'inbox'}
                                    onAddTask={handleAddTask}
                                    onCancel={() => setShowAddTask(false)}
                                />
                            </div>
                        )}

                        {/* Task List */}
                        <div className="space-y-2">
                            {filteredItems.map(item => (
                                <FlowItem 
                                    key={item.id} 
                                    item={item} 
                                    onComplete={handleComplete}
                                    onDelete={handleDelete}
                                    onUpdate={(updates) => handleUpdateItem(item.id, updates)}
                                />
                            ))}
                        </div>

                        {/* Empty State */}
                        {filteredItems.length === 0 && !showAddTask && (
                            <div className="flex flex-col items-center justify-center py-24 opacity-60">
                                <div className="w-16 h-16 bg-zinc-100 dark:bg-dark-surface rounded-full flex items-center justify-center mb-4">
                                    <LayoutGrid size={32} className="text-zinc-300 dark:text-zinc-600" />
                                </div>
                                <div className="text-sm font-medium text-zinc-500 dark:text-zinc-400">
                                    {searchQuery ? 'No results found' : 'Everything is organized'}
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Project Modal */}
            <ProjectModal 
                isOpen={isProjectModalOpen} 
                onClose={() => setIsProjectModalOpen(false)}
                onAdd={handleAddProject}
            />

            {/* Toast Notification */}
            {toast && (
                <div className="fixed bottom-12 right-0 md:right-12 z-50 animate-in slide-in-from-right-10 fade-in duration-300 w-full md:w-auto px-4">
                    <div className="bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 justify-between border border-zinc-800 dark:border-zinc-200">
                         <div className="flex items-center gap-3 font-medium">
                             {toast.type === 'success' && <CheckCircle2 size={18} className="text-brand-400 dark:text-brand-600" />}
                             <span>{toast.message}</span>
                         </div>
                         <button onClick={() => setToast(null)} className="text-white/60 dark:text-zinc-900/40 hover:text-white">
                             <X size={16} />
                         </button>
                    </div>
                </div>
            )}
        </main>
      </div>
    </div>
  );
};

export default App;

export enum Priority {
  P1 = 1, // Critical
  P2 = 2, // High
  P3 = 3, // Medium
  P4 = 4  // Low
}

export type ItemType = 'TASK' | 'NOTE' | 'HABIT';
export type HabitFrequency = 'daily' | 'weekly' | 'monthly';

export interface FlowItem {
  id: string;
  type: ItemType;
  content: string;
  description?: string; // Additional context or AI summary

  // Task specific
  isCompleted?: boolean;
  priority?: Priority;
  dueDate?: string; // ISO Date string
  projectId?: string; // Linked Project ID

  // Habit specific
  streak?: number;
  lastCompletedDate?: string; // YYYY-MM-DD
  frequency?: HabitFrequency;
  history?: string[]; // Array of YYYY-MM-DD completion dates for graph

  // Metadata
  tags?: string[];
  createdAt: string;
  mood?: 'neutral' | 'positive' | 'negative' | 'focused' | 'anxious'; // AI inferred mood
}

export interface Project {
  id: string;
  name: string;
  color: string;
}

export interface ParsedTask {
  content: string;
  description?: string;
  priority?: Priority;
  dueDate?: string;
  projectName?: string;
}

export interface ProcessedItem {
  type: ItemType;
  content: string;
  description?: string;
  priority?: Priority;
  dueDate?: string;
  streak?: number;
  frequency?: HabitFrequency;
  tags?: string[];
  mood?: string;
}

export interface ProcessedInput {
  items: ProcessedItem[];
  summary?: string;
}

export type Task = FlowItem;

export interface ViewState {
  type: 'HOME' | 'TASKS' | 'HABITS' | 'JOURNAL' | 'PROJECT' | 'TAG' | 'CALENDAR';
  id?: string; // projectId or tagName
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessedInput, ParsedTask } from "../types";

export const processTextEntry = async (textInput: string): Promise<ProcessedInput | null> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const now = new Date();
    const dateContext = `Today is ${now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}.`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `
                Analyze this input for EchoFlow: "${textInput}". 
                ${dateContext}
                Classify into tasks, notes, or habits. 
                For tasks, calculate precise YYYY-MM-DD due dates if relative time is mentioned (e.g. "next Monday").
                For habits, detect frequency (daily, weekly, monthly).
            `,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        items: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
                                    content: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    priority: { type: Type.INTEGER },
                                    dueDate: { type: Type.STRING },
                                    mood: { type: Type.STRING },
                                    streak: { type: Type.INTEGER },
                                    frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
                                    tags: { type: Type.ARRAY, items: { type: Type.STRING } }
                                },
                                required: ["type", "content"]
                            }
                        }
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : null;
    } catch (e) {
        console.error("Text processing error", e);
        return null;
    }
}

export const parseTaskWithGemini = async (rawInput: string, projectNames: string[]): Promise<ParsedTask | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const now = new Date();
  const dateContext = `Today is ${now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `
        You are a smart task parser.
        ${dateContext}
        Spaces: ${JSON.stringify(projectNames)}

        Input: "${rawInput}"

        Extract:
        - content: clear task title
        - description: extra details
        - priority: 1 (Urgent) to 4 (Low). Default 4.
        - dueDate: YYYY-MM-DD (Calculate based on today's date)
        - projectName: Exact match from provided list if applicable (Spaces)
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            content: { type: Type.STRING },
            description: { type: Type.STRING },
            priority: { type: Type.INTEGER },
            dueDate: { type: Type.STRING },
            projectName: { type: Type.STRING }
          },
          required: ["content"]
        }
      }
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("Task parsing error", error);
    return null;
  }
};

export const suggestSubtasks = async (taskContent: string): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `List 3-5 subtasks for: "${taskContent}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return response.text ? JSON.parse(response.text) : [];
  } catch (error) {
