    return [];
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, X, Activity } from 'lucide-react';
import { GoogleGenAI, Type, Schema } from '@google/genai';
import { ProcessedInput } from '../types';

interface VoiceCaptureProps {
  onProcessed: (result: ProcessedInput) => void;
}

const VoiceCapture: React.FC<VoiceCaptureProps> = ({ onProcessed }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [volume, setVolume] = useState(0);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  // Refs
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const animationFrameRef = useRef<number>(0);
  const mountedRef = useRef(true);

  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
      stopResources();
      cancelAnimationFrame(animationFrameRef.current);
    };
  }, []);

  // Define the schema for structured extraction
  const extractionSchema: Schema = {
      type: Type.OBJECT,
      properties: {
        items: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
              content: { type: Type.STRING, description: "The main text of the item" },
              description: { type: Type.STRING, description: "Any additional details mentioned" },
              priority: { type: Type.INTEGER, description: "1 (High) to 4 (Low)" },
              dueDate: { type: Type.STRING, description: "YYYY-MM-DD format if mentioned" },
              streak: { type: Type.INTEGER },
              frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["type", "content"]
          }
        },
        summary: { type: Type.STRING, description: "A brief confirmation message of what was captured" }
      },
      required: ['items']
  };

  const startRecording = async () => {
    try {
      setErrorMessage(null);
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      // Visualizer Setup
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioContextRef.current = audioContext;
      const source = audioContext.createMediaStreamSource(stream);
      const analyser = audioContext.createAnalyser();
      analyser.fftSize = 64;
      source.connect(analyser);
      analyserRef.current = analyser;

      // Recorder Setup
      const mimeType = MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : 'audio/mp4';
      const mediaRecorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        if (!mountedRef.current) return;
        const blob = new Blob(chunksRef.current, { type: mimeType });
        await processAudio(blob, mimeType);
      };

      mediaRecorder.start();
      setIsRecording(true);
      visualize();

    } catch (e) {
      console.error("Microphone access failed", e);
      setErrorMessage("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
        mediaRecorderRef.current.stop();
    }
    setIsRecording(false);
    stopResources(); // Stop stream/context immediately to release mic
  };

  const stopResources = () => {
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(t => t.stop());
          mediaStreamRef.current = null;
      }
      if (audioContextRef.current) {
          audioContextRef.current.close();
          audioContextRef.current = null;
      }
      if (animationFrameRef.current) {
          cancelAnimationFrame(animationFrameRef.current);
      }
  };

  const visualize = () => {
      if (!analyserRef.current) return;
      const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
      analyserRef.current.getByteFrequencyData(dataArray);

      // Calculate average volume for visualization
      let sum = 0;
      for (let i = 0; i < dataArray.length; i++) sum += dataArray[i];
      const avg = sum / dataArray.length;

      setVolume(avg / 128); // Normalize somewhat

      if (mountedRef.current) {
          animationFrameRef.current = requestAnimationFrame(visualize);
      }
  };

  const processAudio = async (blob: Blob, mimeType: string) => {
      setIsProcessing(true);
      try {
          const base64Data = await blobToBase64(blob);
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

          // Inject current date context for accurate relative date parsing
          const now = new Date();
          const dateContext = `Today is ${now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })} (YYYY-MM-DD: ${now.getFullYear()}-${String(now.getMonth()+1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}).`;

          const response = await ai.models.generateContent({
            model: 'gemini-2.0-flash-exp',
            contents: {
                parts: [
                    { 
                        inlineData: { 
                            mimeType: mimeType, 
                            data: base64Data 
                        } 
                    },
                    { 
                        text: `You are an intelligent productivity assistant. 
                        ${dateContext}
                        Listen to the audio and extract any tasks, habits, or notes.
                        Use the date context to correctly calculate specific YYYY-MM-DD due dates for relative terms like "tomorrow", "next Friday", or "in 3 days".
                        Return a JSON object with the extracted items.` 
                    }
                ]
            },
            config: {
                responseMimeType: "application/json",
                responseSchema: extractionSchema
            }
          });

          const result = response.text ? JSON.parse(response.text) : null;
          if (result) {
              onProcessed(result);
          }
      } catch (e) {
          console.error("Processing failed", e);
          setErrorMessage("Failed to process audio. Please try again.");
      } finally {
          if (mountedRef.current) setIsProcessing(false);
      }
  };

  const blobToBase64 = (blob: Blob): Promise<string> => {
      return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onloadend = () => {
              const result = reader.result as string;
              // Remove data URL prefix (e.g., "data:audio/webm;base64,")
              const base64 = result.split(',')[1];
              resolve(base64);
          };
          reader.onerror = reject;
          reader.readAsDataURL(blob);
      });
  };

  return (
    <div className="fixed bottom-0 left-0 md:left-[260px] right-0 p-6 flex flex-col items-center justify-end z-30 pointer-events-none">

       {/* Error Overlay */}
       {errorMessage && (
           <div className="pointer-events-auto mb-4 bg-red-500/90 backdrop-blur-xl text-white px-6 py-3 rounded-2xl shadow-xl flex items-center gap-3 animate-in slide-in-from-bottom-5 fade-in duration-300">
               <Activity size={18} />
               <span className="text-sm font-medium">{errorMessage}</span>
               <button onClick={() => setErrorMessage(null)} className="ml-2 hover:bg-white/20 p-1 rounded-full"><X size={14}/></button>
           </div>
       )}

       {/* Status/Visualizer Overlay */}
       {(isRecording || isProcessing) && (
           <div className="pointer-events-auto mb-6 bg-zinc-900/90 backdrop-blur-xl text-white px-6 py-4 rounded-3xl shadow-2xl flex flex-col items-center gap-2 animate-in slide-in-from-bottom-10 fade-in duration-300 border border-zinc-800 max-w-lg w-full text-center">
               <div className="flex items-center gap-2 mb-1">
                   {isRecording && (
                        <span className="flex items-center gap-1.5 text-xs font-bold uppercase tracking-wider text-emerald-400">
                             <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"/>
                             Listening
                        </span>
                   )}
                   {isProcessing && (
                        <span className="flex items-center gap-1.5 text-xs font-bold uppercase tracking-wider text-sky-400">
                             <Loader2 size={12} className="animate-spin" />
                             Reasoning
                        </span>
                   )}
               </div>

               {isProcessing && (
                   <p className="text-sm text-zinc-300 italic">Processing your thoughts...</p>
               )}

               {/* Visualizer */}
               <div className="flex items-center gap-1 h-8 mt-2">
                   {[...Array(8)].map((_, i) => (
                       <div 
                           key={i}
                           className={`w-1.5 rounded-full transition-all duration-75 ${isProcessing ? 'bg-sky-400 animate-pulse' : 'bg-emerald-500'}`}
                           style={{ 
                               height: isProcessing 
                                ? '40%' 
                                : `${Math.max(20, Math.min(100, volume * 1000 * (Math.random() + 0.5)))}%`,
                               opacity: 0.8 
                           }}
                       />
                   ))}
               </div>
           </div>
       )}

      {/* Main Control */}
      <div className="pointer-events-auto flex items-center gap-4">
        <button
            onClick={isRecording ? stopRecording : startRecording}
            disabled={isProcessing}
            className={`
            relative flex items-center justify-center w-16 h-16 rounded-full shadow-2xl transition-all duration-300 transform
            ${isProcessing 
                ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed scale-95'
                : isRecording 
                    ? 'bg-zinc-800 text-rose-500 ring-4 ring-rose-500/20 scale-100 hover:scale-105' 
                    : 'bg-brand-600 text-white hover:bg-brand-700 hover:scale-110 shadow-brand-500/40'
            }
            `}
        >
            {isRecording ? (
                <Square size={24} fill="currentColor" />
            ) : isProcessing ? (
                <Loader2 size={24} className="animate-spin" />
            ) : (
                <Mic size={28} />
            )}
        </button>
      </div>

      <div className="h-6 mt-4 text-xs font-medium text-zinc-400 dark:text-zinc-500 text-center transition-opacity duration-300">
        {isRecording ? "Tap to finish" : isProcessing ? "Just a moment..." : "Tap to speak"}
      </div>
    </div>
  );
};

export default VoiceCapture;
